{
    "level": "B1",
    "intro": "У цій темі ти навчишся вживати <strong>collective nouns</strong> на кшталт <strong>team, family, staff, police</strong> і правильно узгоджувати їх із дієсловом.",
    "rules": [
        {
            "label": "ONE GROUP",
            "color": "emerald",
            "text": "Коли група сприймається як <strong>одне ціле</strong>, часто вживаємо форму однини.",
            "example": "The team is ready."
        },
        {
            "label": "MEMBERS",
            "color": "blue",
            "text": "Коли увага на <strong>членах групи</strong>, особливо в BrE, можлива множина.",
            "example": "The team are wearing different shirts."
        },
        {
            "label": "SPECIAL CASES",
            "color": "amber",
            "text": "Деякі слова мають власні правила: <strong>police</strong> майже завжди в множині.",
            "example": "The police are investigating the case."
        }
    ]
}

{
    "title": "1. Поширені collective nouns",
    "intro": "Запам’ятай типові слова та їхню поведінку.",
    "items": [
        {
            "label": "часто однина",
            "title": "team / family / class / committee",
            "subtitle": "The family is happy."
        },
        {
            "label": "можлива однина або множина",
            "title": "staff / audience / government",
            "subtitle": "залежить від значення та варіанта англійської"
        },
        {
            "label": "звичайно множина",
            "title": "police",
            "subtitle": "The police are here."
        },
        {
            "label": "значення вирішує",
            "title": "couple / crew / company",
            "subtitle": "one unit or separate members?"
        }
    ]
}

{
    "title": "2. Як вибирати форму",
    "sections": [
        {
            "label": "Група як одне ціле",
            "color": "emerald",
            "description": "Коли говоримо про групу як про <strong>єдину одиницю</strong>, форма однини звучить природно.",
            "examples": [
                {
                    "en": "The team is ready for the match.",
                    "ua": "Команда готова до матчу."
                },
                {
                    "en": "My family lives in Lviv.",
                    "ua": "Моя сім’я живе у Львові."
                },
                {
                    "en": "The committee has made its decision.",
                    "ua": "Комітет ухвалив своє рішення."
                }
            ]
        },
        {
            "label": "Члени групи окремо",
            "color": "blue",
            "description": "У британській англійській множина можлива, коли акцент на <strong>окремих людях усередині групи</strong>.",
            "examples": [
                {
                    "en": "The team are wearing different shirts.",
                    "ua": "Члени команди в різних футболках."
                },
                {
                    "en": "My family are all coming at different times.",
                    "ua": "Усі члени моєї сім’ї приїжджають у різний час."
                },
                {
                    "en": "The staff are arguing about the schedule.",
                    "ua": "Працівники сперечаються про розклад."
                }
            ],
            "note": "В американській англійській однина тут зустрічається частіше."
        },
        {
            "label": "Особливі випадки",
            "color": "amber",
            "description": "<strong>Police</strong> майже завжди поєднується з множиною; інші слова залежать від значення.",
            "examples": [
                {
                    "en": "The police are outside.",
                    "ua": "Поліція надворі."
                },
                {
                    "en": "The audience was silent.",
                    "ua": "Аудиторія мовчала."
                },
                {
                    "en": "The audience were taking their seats.",
                    "ua": "Люди в залі займали свої місця."
                }
            ],
            "note": "Одна й та сама назва може мати різну форму залежно від фокусу висловлювання."
        }
    ]
}

{
    "title": "3. Типові помилки",
    "items": [
        {
            "label": "Помилка 1",
            "color": "rose",
            "title": "Police з одниною.",
            "wrong": "The police is here.",
            "right": "✅ <span class=\"font-mono\">The police are here.</span>"
        },
        {
            "label": "Помилка 2",
            "color": "amber",
            "title": "Автоматична множина для всіх collective nouns.",
            "wrong": "My family are small. <span class=\"text-slate-500\">(якщо йдеться про сім’ю як одну одиницю)</span>",
            "right": "✅ <span class=\"font-mono\">My family is small.</span>"
        },
        {
            "label": "Помилка 3",
            "color": "sky",
            "title": "Ігнорування значення.",
            "wrong": "The team is wearing different shirts. <span class=\"text-slate-500\">(якщо фокус на гравцях окремо)</span>",
            "right": "✅ <span class=\"font-mono\">The team are wearing different shirts.</span>"
        }
    ]
}

{
    "title": "4. Короткий конспект",
    "items": [
        "Collective nouns називають групу людей або речей як одну одиницю.",
        "Однина підходить, коли група сприймається як ціле.",
        "Множина можлива, коли важливі окремі члени групи, особливо в BrE.",
        "<strong>Police</strong> зазвичай вживається з множиною.",
        "Вибір форми залежить не лише від слова, а й від значення в конкретному реченні."
    ]
}

